import React, { useState, useEffect, useCallback } from "react";
import { X, Plus, FileText, Star, Trash2, Loader2 } from "lucide-react";
import { useAuth } from "../context/AuthContext";
import { API_URL } from "../config/env";

const Templates = ({ onUseTemplate }) => {
  const { getAuthHeaders } = useAuth();
  const [templates, setTemplates] = useState({ user: [], public: [] });
  const [showModal, setShowModal] = useState(false);
  const [activeTab, setActiveTab] = useState("user");
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    description: "",
    title: "",
    content: "",
    color: "#FFE4B5",
    category: "personal",
    tags: [],
  });

  const fetchTemplates = useCallback(async () => {
    try {
      const response = await fetch(`${API_URL}/templates`, {
        headers: getAuthHeaders(),
      });
      const data = await response.json();
      setTemplates({
        user: Array.isArray(data.user) ? data.user : [],
        public: Array.isArray(data.public) ? data.public : [],
      });
    } catch (error) {
      console.error("Lỗi khi tải templates:", error);
    }
  }, [getAuthHeaders]);

  useEffect(() => {
    fetchTemplates();
  }, [fetchTemplates]);

  const handleUseTemplate = async (templateId) => {
    try {
      const response = await fetch(
        `${API_URL}/templates/${templateId}/use`,
        {
          method: "POST",
          headers: getAuthHeaders(),
        }
      );
      const note = await response.json();
      if (onUseTemplate) {
        onUseTemplate(note);
      }
      await fetchTemplates();
      alert("✅ Đã sử dụng template thành công!");
    } catch (error) {
      console.error("Lỗi:", error);
      alert("❌ Không thể sử dụng template!");
    }
  };

  const handleCreateTemplate = async (e) => {
    e.preventDefault();
    if (!formData.name.trim()) {
      alert("⚠️ Vui lòng nhập tên template!");
      return;
    }
    
    setLoading(true);
    try {
      const response = await fetch(`${API_URL}/templates`, {
        method: "POST",
        headers: getAuthHeaders(),
        body: JSON.stringify(formData),
      });
      
      if (response.ok) {
        await fetchTemplates();
        setShowModal(false);
        setFormData({
          name: "",
          description: "",
          title: "",
          content: "",
          color: "#FFE4B5",
          category: "personal",
          tags: [],
        });
        alert("✅ Tạo template thành công!");
      } else {
        const errorData = await response.json();
        alert(`❌ Lỗi: ${errorData.error || "Không thể tạo template"}`);
      }
    } catch (error) {
      console.error("Lỗi:", error);
      alert("❌ Lỗi kết nối server. Vui lòng thử lại!");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Bạn có chắc muốn xóa template này?")) return;
    try {
      const response = await fetch(`${API_URL}/templates/${id}`, {
        method: "DELETE",
        headers: getAuthHeaders(),
      });
      if (response.ok) {
        await fetchTemplates();
        alert("✅ Đã xóa template!");
      } else {
        alert("❌ Không thể xóa template!");
      }
    } catch (error) {
      console.error("Lỗi:", error);
      alert("❌ Lỗi khi xóa template!");
    }
  };

  return (
    <>
      <div className="space-y-4">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h3 className="text-lg font-bold text-gray-800 dark:text-white flex items-center gap-2">
              <FileText size={20} className="text-blue-500" />
              Templates
            </h3>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
              Tạo và quản lý các mẫu ghi chú của bạn
            </p>
          </div>
          <button
            onClick={() => setShowModal(true)}
            className="px-4 py-2 bg-gradient-to-r from-blue-500 to-purple-600 text-white rounded-xl hover:from-blue-600 hover:to-purple-700 transition-all shadow-lg hover:shadow-xl text-sm font-semibold flex items-center gap-2"
          >
            <Plus size={16} />
            Tạo mới
          </button>
        </div>

        <div className="flex gap-2 border-b-2 border-gray-200 dark:border-gray-700">
          <button
            onClick={() => setActiveTab("user")}
            className={`px-4 py-2.5 font-semibold transition-all relative ${
              activeTab === "user"
                ? "text-blue-600 dark:text-blue-400"
                : "text-gray-500 hover:text-gray-700 dark:hover:text-gray-300"
            }`}
          >
            Của tôi
            <span className={`ml-2 px-2 py-0.5 rounded-full text-xs ${
              activeTab === "user" 
                ? "bg-blue-100 dark:bg-blue-900 text-blue-600 dark:text-blue-300"
                : "bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-400"
            }`}>
              {templates.user.length}
            </span>
            {activeTab === "user" && (
              <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-gradient-to-r from-blue-500 to-purple-600" />
            )}
          </button>
          <button
            onClick={() => setActiveTab("public")}
            className={`px-4 py-2.5 font-semibold transition-all relative ${
              activeTab === "public"
                ? "text-blue-600 dark:text-blue-400"
                : "text-gray-500 hover:text-gray-700 dark:hover:text-gray-300"
            }`}
          >
            Công khai
            <span className={`ml-2 px-2 py-0.5 rounded-full text-xs ${
              activeTab === "public" 
                ? "bg-blue-100 dark:bg-blue-900 text-blue-600 dark:text-blue-300"
                : "bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-400"
            }`}>
              {templates.public.length}
            </span>
            {activeTab === "public" && (
              <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-gradient-to-r from-blue-500 to-purple-600" />
            )}
          </button>
        </div>

        <div className="space-y-3 max-h-80 overflow-y-auto pr-2">
          {(activeTab === "user" ? templates.user : templates.public).length === 0 ? (
            <div className="text-center py-8">
              <FileText size={48} className="mx-auto text-gray-300 dark:text-gray-600 mb-3" />
              <p className="text-gray-500 dark:text-gray-400">
                {activeTab === "user" 
                  ? "Chưa có template nào. Tạo template đầu tiên của bạn!"
                  : "Chưa có template công khai nào"
                }
              </p>
            </div>
          ) : (
            (activeTab === "user" ? templates.user : templates.public).map((template) => (
              <div
                key={template._id}
                className="group p-4 bg-gradient-to-br from-white to-gray-50 dark:from-gray-800 dark:to-gray-750 border-2 border-gray-200 dark:border-gray-700 rounded-xl hover:border-blue-400 dark:hover:border-blue-600 hover:shadow-lg transition-all duration-200"
              >
                <div className="flex items-start justify-between gap-3">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <h4 className="font-bold text-gray-800 dark:text-white truncate">
                        {template.name}
                      </h4>
                      {template.isPublic && (
                        <span className="flex-shrink-0 px-2 py-0.5 bg-blue-100 dark:bg-blue-900 text-blue-600 dark:text-blue-300 rounded-full text-xs font-semibold inline-flex items-center gap-1">
                          <Star size={12} />
                          Public
                        </span>
                      )}
                    </div>
                    {template.description && (
                      <p className="text-sm text-gray-600 dark:text-gray-400 line-clamp-2">
                        {template.description}
                      </p>
                    )}
                  </div>
                  <div className="flex gap-2 flex-shrink-0">
                    <button
                      onClick={() => handleUseTemplate(template._id)}
                      className="px-3 py-1.5 bg-gradient-to-r from-green-500 to-emerald-600 text-white rounded-lg text-sm font-semibold hover:from-green-600 hover:to-emerald-700 transition-all shadow-md hover:shadow-lg"
                    >
                      Dùng
                    </button>
                    {activeTab === "user" && (
                      <button
                        onClick={() => handleDelete(template._id)}
                        className="p-1.5 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30 rounded-lg transition-colors"
                        title="Xóa template"
                      >
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
          <div className="bg-white dark:bg-gray-800 rounded-3xl shadow-2xl p-8 max-w-2xl w-full max-h-[90vh] overflow-y-auto border-2 border-gray-100 dark:border-gray-700">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <FileText size={28} className="text-blue-500" />
                Tạo Template
              </h3>
              <button 
                onClick={() => setShowModal(false)}
                className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"
              >
                <X size={24} className="text-gray-600 dark:text-gray-300" />
              </button>
            </div>
            <form onSubmit={handleCreateTemplate} className="space-y-6">
              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Tên template
                </label>
                <input
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  required
                  className="w-full px-4 py-3 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-xl focus:border-blue-500 focus:outline-none transition-colors bg-gray-50"
                  placeholder="Nhập tên template..."
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Mô tả
                </label>
                <input
                  type="text"
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  className="w-full px-4 py-3 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-xl focus:border-blue-500 focus:outline-none transition-colors bg-gray-50"
                  placeholder="Mô tả ngắn về template..."
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Tiêu đề mặc định
                </label>
                <input
                  type="text"
                  value={formData.title}
                  onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                  className="w-full px-4 py-3 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-xl focus:border-blue-500 focus:outline-none transition-colors bg-gray-50"
                  placeholder="Tiêu đề sẽ được điền tự động khi dùng template..."
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Nội dung mặc định
                </label>
                <textarea
                  value={formData.content}
                  onChange={(e) => setFormData({ ...formData, content: e.target.value })}
                  rows={6}
                  className="w-full px-4 py-3 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-xl focus:border-blue-500 focus:outline-none transition-colors bg-gray-50 resize-none"
                  placeholder="Nội dung sẽ được điền tự động khi dùng template..."
                />
              </div>
              <div className="flex gap-3 pt-4">
                <button
                  type="button"
                  onClick={() => {
                    if (!loading) {
                      setShowModal(false);
                    }
                  }}
                  disabled={loading}
                  className="flex-1 px-4 py-3 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-xl font-semibold hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  Hủy
                </button>
                <button
                  type="submit"
                  disabled={loading}
                  className="flex-1 px-4 py-3 bg-gradient-to-r from-blue-500 to-purple-600 text-white rounded-xl font-semibold hover:from-blue-600 hover:to-purple-700 transition-all shadow-lg hover:shadow-xl disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                  {loading ? (
                    <>
                      <Loader2 size={18} className="animate-spin" />
                      Đang tạo...
                    </>
                  ) : (
                    "Tạo Template"
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </>
  );
};

export default Templates;
